-- RealityDB SaaS Template | Seed: 42 | ~170 rows
-- Lifecycle: cancelled subscriptions → next_billing_at = NULL
-- Temporal: subscriptions.started_at < subscriptions.next_billing_at
-- Weights: plan free=60% pro=30% enterprise=10% | status active=60% trial=15% cancelled=15% past_due=10%

CREATE TABLE organizations (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name TEXT NOT NULL,
  industry TEXT NOT NULL,
  plan TEXT NOT NULL,
  employee_count INTEGER NOT NULL,
  created_at TIMESTAMP NOT NULL
);

CREATE TABLE users (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  org_id UUID NOT NULL REFERENCES organizations(id),
  email TEXT NOT NULL,
  name TEXT NOT NULL,
  role TEXT NOT NULL,
  last_login TIMESTAMP,
  created_at TIMESTAMP NOT NULL
);

CREATE TABLE subscriptions (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  org_id UUID NOT NULL REFERENCES organizations(id),
  plan TEXT NOT NULL,
  status TEXT NOT NULL,
  amount NUMERIC(10,2) NOT NULL,
  started_at TIMESTAMP NOT NULL,
  next_billing_at TIMESTAMP,
  created_at TIMESTAMP NOT NULL
);

CREATE TABLE payments (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  subscription_id UUID NOT NULL REFERENCES subscriptions(id),
  amount NUMERIC(10,2) NOT NULL,
  status TEXT NOT NULL,
  method TEXT NOT NULL,
  processed_at TIMESTAMP,
  created_at TIMESTAMP NOT NULL
);

-- Organizations (20)

-- Users (50) — roles: owner=5% admin=15% member=60% viewer=20%

-- Subscriptions (30) — plan: free=60% pro=30% enterprise=10% | status: active=60% trial=15% cancelled=15% past_due=10%
-- LIFECYCLE: cancelled → next_billing_at = NULL

-- Payments (70) — status: completed=70% pending=15% failed=10% refunded=5% | method: card=60% bank=25% paypal=15%
